// And groups predicates with the AND operator between them.
func And(predicates ...predicate.ShopProduct) predicate.ShopProduct {
	return predicate.ShopProduct(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.ShopProduct) predicate.ShopProduct {
	return predicate.ShopProduct(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.ShopProduct) predicate.ShopProduct {
	return predicate.ShopProduct(sql.NotPredicates(p))
}
